
window.downloadInvoice = function(invoiceData, sessionData) {
  if (!window.html2pdf) {
    var script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js';
    script.onload = function() {
      _generatePdf(invoiceData, sessionData);
    };
    document.head.appendChild(script);
  } else {
    _generatePdf(invoiceData, sessionData);
  }
};

function _generatePdf(invoiceData, sessionData) {
  var wrapper = document.createElement('div');
  wrapper.style.position = 'fixed';
  wrapper.style.top = '0';
  wrapper.style.left = '0';
  wrapper.style.zIndex = '-9999';
  wrapper.style.opacity = '0.01';
  wrapper.style.pointerEvents = 'none';
  document.body.appendChild(wrapper);

  var date = new Date(invoiceData.date || new Date());
  var formattedDate = date.toLocaleDateString('en-GB').replace(/\//g, '.');
  var shortTxn = invoiceData.txnId ? invoiceData.txnId.substring(3, 9) : '000000';
  
  var methods = { card: 'Credit/Debit Card', upi: 'UPI', netbanking: 'Net Banking' };
  var payMethod = methods[invoiceData.method] || invoiceData.method || 'Card';

  var itemsHtml = '';
  var subtotal = 0;
  
  (invoiceData.items || []).forEach(function(item) {
    var price = parseFloat(item.price);
    var qty = parseInt(item.qty || 1);
    var lineTotal = price * qty;
    subtotal += lineTotal;

    itemsHtml += `
      <tr>
        <td class="td-desc">${item.description}</td>
        <td class="td-center">${qty}</td>
        <td class="td-center">₹${price.toLocaleString('en-IN')}</td>
        <td class="td-right">₹${lineTotal.toLocaleString('en-IN')}</td>
      </tr>
    `;
  });

  var totalDiscount = invoiceData.discount ? parseFloat(invoiceData.discount) : 0;
  var taxableAmount = subtotal - totalDiscount;
  var tax = taxableAmount * 0.18; // 18% GST
  var grandTotal = taxableAmount + tax;

  var html = `
    <style>
      .pdf-wrap {
        width: 794px; /* A4 width */
        min-height: 1123px; /* A4 height */
        background: #fafaf7;
        font-family: 'DM Sans', sans-serif;
        color: #1e3a5f;
        position: relative;
        overflow: hidden;
      }
      .pdf-header {
        background: #5b694b;
        height: 280px;
        position: relative;
        overflow: hidden;
        color: #ffffff;
        padding: 50px 60px;
        box-sizing: border-box;
      }
      .circle-1 {
        position: absolute;
        width: 800px;
        height: 800px;
        border-radius: 50%;
        background: rgba(255,255,255,0.04);
        top: -300px;
        right: -200px;
      }
      .circle-2 {
        position: absolute;
        width: 600px;
        height: 600px;
        border-radius: 50%;
        background: rgba(0,0,0,0.06);
        bottom: -300px;
        left: -150px;
      }
      .header-title {
        font-size: 3.5rem;
        font-weight: 700;
        letter-spacing: 0.15em;
        margin: 0 0 10px 0;
      }
      .header-meta {
        font-size: 0.95rem;
        letter-spacing: 0.1em;
        font-weight: 600;
        line-height: 1.8;
      }
      .header-logo {
        position: absolute;
        top: 50px;
        right: 60px;
        height: 160px;
      }
      .client-card {
        background: #ffffff;
        border-radius: 12px;
        margin: -40px 60px 0;
        padding: 24px 32px;
        display: flex;
        justify-content: space-between;
        align-items: center;
        position: relative;
        z-index: 10;
        box-shadow: 0 4px 15px rgba(0,0,0,0.05); /* very soft shadow like image */
      }
      .client-label {
        font-size: 0.8rem;
        font-weight: 700;
        color: #9a9d7e;
        text-transform: uppercase;
        margin-bottom: 6px;
      }
      .client-name {
        font-size: 1.6rem;
        font-weight: 700;
        color: #4a5d3f;
      }
      .client-details {
        text-align: right;
        font-size: 0.85rem;
        color: #3d4228;
        line-height: 1.6;
      }
      .table-area {
        padding: 40px 60px 20px;
      }
      .inv-table {
        width: 100%;
        border-collapse: collapse;
        margin-bottom: 20px;
      }
      .inv-table th {
        font-weight: 700;
        font-size: 0.95rem;
        color: #1e3a5f;
        padding: 14px 8px;
        border-top: 2px solid #1e3a5f;
        border-bottom: 1.5px solid #1e3a5f;
      }
      .inv-table th:first-child { text-align: left; }
      .inv-table th.center { text-align: center; }
      .inv-table th.right { text-align: right; }
      .td-desc {
        padding: 16px 8px; font-size: 0.95rem; color: #1e3a5f; font-weight: 600; text-align: left;
        border-bottom: 1px solid rgba(0,0,0,0.04);
      }
      .td-center {
        padding: 16px 8px; font-size: 0.95rem; color: #1e3a5f; font-weight: 600; text-align: center;
        border-bottom: 1px solid rgba(0,0,0,0.04);
      }
      .td-right {
        padding: 16px 8px; font-size: 0.95rem; color: #1e3a5f; font-weight: 600; text-align: right;
        border-bottom: 1px solid rgba(0,0,0,0.04);
      }
      .totals-area {
        display: flex;
        justify-content: flex-end;
        padding: 0 60px 40px;
      }
      .totals-grid {
        display: grid;
        grid-template-columns: 120px 100px;
        gap: 12px;
        font-size: 0.95rem;
        color: #1e3a5f;
      }
      .totals-grid .label { font-weight: 700; }
      .totals-grid .val { text-align: right; font-weight: 600; }
      
      .pay-total-area {
        margin: 0 60px;
        border-top: 2px solid #1e3a5f;
        padding-top: 20px;
        display: flex;
        justify-content: space-between;
      }
      .pay-details h4 {
        font-size: 1rem;
        font-weight: 700;
        margin: 0 0 10px 0;
        color: #1e3a5f;
      }
      .pay-grid {
        display: grid;
        grid-template-columns: auto auto;
        column-gap: 16px;
        row-gap: 4px;
        font-size: 0.85rem;
        color: #1e3a5f;
      }
      .pay-grid .label { font-weight: 600; }
      .grand-total-block {
        display: flex;
        align-items: center;
        gap: 30px;
      }
      .grand-total-block .label {
        font-size: 1.2rem;
        font-weight: 700;
        color: #1e3a5f;
      }
      .grand-total-block .val {
        font-size: 1.4rem;
        font-weight: 700;
        color: #1e3a5f;
      }
      
      .footer-card {
        background: #ffffff;
        border-radius: 12px;
        margin: 40px 60px 0;
        padding: 24px 32px;
        display: flex;
        justify-content: space-between;
        align-items: center;
        box-shadow: 0 4px 15px rgba(0,0,0,0.03);
      }
      .footer-contact h4 {
        font-size: 1rem;
        font-weight: 700;
        color: #1e3a5f;
        margin: 0 0 8px 0;
      }
      .footer-contact p {
        font-size: 0.85rem;
        color: #1e3a5f;
        margin: 0;
        line-height: 1.5;
        font-weight: 500;
      }
      .footer-thanks {
        font-size: 1.6rem;
        font-weight: 700;
        color: #1e3a5f;
      }
      .bottom-bar {
        position: absolute;
        bottom: 0;
        left: 0;
        width: 100%;
        height: 40px;
        background: linear-gradient(135deg, #44543b 0%, #687955 100%);
      }
    </style>
    <div class="pdf-wrap">
      <div class="pdf-header">
        <div class="circle-1"></div>
        <div class="circle-2"></div>
        <div style="position: relative; z-index: 5;">
          <h1 class="header-title">INVOICE</h1>
          <div class="header-meta">
            INVOICE NO: ${shortTxn}<br>
            ${formattedDate}
          </div>
        </div>
        <img src="data:image/png;base64," class="header-logo" style="z-index: 5;">
      </div>

      <div class="client-card">
        <div>
          <div class="client-label">Invoice To:</div>
          <div class="client-name">${sessionData.name || 'CLIENT'}</div>
        </div>
        <div class="client-details">
          ${sessionData.email || 'email@example.com'}<br>
          ${sessionData.phone || ''}
        </div>
      </div>

      <div class="table-area">
        <table class="inv-table">
          <thead>
            <tr>
              <th>Description</th>
              <th class="center">Qty</th>
              <th class="center">Cost</th>
              <th class="right">Subtotal</th>
            </tr>
          </thead>
          <tbody>
            ${itemsHtml}
          </tbody>
        </table>
      </div>

      <div class="totals-area">
        <div class="totals-grid">
          <div class="label">Subtotal</div>
          <div class="val">₹${subtotal.toLocaleString('en-IN')}</div>
          
          ${(totalDiscount > 0) ? '<div class="label">Discount</div><div class="val">-₹' + totalDiscount.toLocaleString('en-IN') + '</div>' : ''}

          <div class="label">Tax (18% GST)</div>
          <div class="val">₹${Math.round(tax).toLocaleString('en-IN')}</div>
        </div>
      </div>

      <div class="pay-total-area">
        <div class="pay-details">
          <h4>Payment Details:</h4>
          <div class="pay-grid">
            <div class="label">Method:</div> <div>${payMethod}</div>
            <div class="label">Status:</div> <div style="color: #4a5d3f; font-weight: 700;">Paid</div>
            ${invoiceData.txnId ? '<div class="label">Txn ID:</div> <div>' + invoiceData.txnId + '</div>' : ''}
          </div>
        </div>
        <div class="grand-total-block">
          <div class="label">Total</div>
          <div class="val">₹${Math.round(grandTotal).toLocaleString('en-IN')}</div>
        </div>
      </div>

      <div class="footer-card">
        <div class="footer-contact">
          <h4>Contact Us</h4>
          <p>
            S.No 340B/1A3B1, Vinayaka Avenue,<br>
            Okkiyam Thoraipakkam,<br>
            OMR, Chennai – 600 097.<br>
            www.nribridgeindia.com | +91 7824844999
          </p>
        </div>
        <div class="footer-thanks">
          Thank You!
        </div>
      </div>

      <div class="bottom-bar"></div>
    </div>
  `;

  wrapper.innerHTML = html;

  var element = wrapper.querySelector('.pdf-wrap');
  var opt = {
    margin:       0,
    filename:     'Invoice_' + (invoiceData.txnId || '123') + '.pdf',
    image:        { type: 'jpeg', quality: 1 },
    html2canvas:  { scale: 2, useCORS: true, scrollY: 0 },
    jsPDF:        { unit: 'px', format: [794, 1123], orientation: 'portrait' }
  };

  html2pdf().set(opt).from(element).save().then(function() {
    setTimeout(function() {
      document.body.removeChild(wrapper);
    }, 2000);
  });
}
